SELECT [KIMO-FASHION Sales Order Line].[Model Item No_], Item.Description, Item.[Description 2], [KIMO-FASHION Sales Order Line].[Color Code], Item.[Line Code], Sum(Val([Quantity])) AS qty, Item.[Vendor No_], Vendor.Name AS [Vendor Name], Item.[Manufacturer Code], Vendor_1.Name AS [Manufaturer Name], Item.[Collection Code], Item.[season Code], [KIMO-FASHION Sales Order Hdr].[Assigned Sales Document No_], Customer.No_, Customer.Name, [KIMO-FASHION Sales Order Hdr].[trademark code], [KIMO-FASHION Sales Order Line].Type, [KIMO-FASHION Sales Order Hdr].[Create SO Date Time], [KIMO-FASHION Sales Order Hdr].[Release SO Date Time], [KIMO-FASHION Sales Order Line].[KIMO_FASHION SO Reference], [KIMO-FASHION Sales Order Hdr].[KIMO Document Type]
FROM (((([KIMO-FASHION Sales Order Line] INNER JOIN [KIMO-FASHION Sales Order Hdr] ON [KIMO-FASHION Sales Order Line].[Header Entry No_] = [KIMO-FASHION Sales Order Hdr].[Entry No_]) INNER JOIN Customer ON [KIMO-FASHION Sales Order Hdr].[Sell-to Customer No_] = Customer.No_) INNER JOIN Item ON [KIMO-FASHION Sales Order Line].[Model Item No_] = Item.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.[Manufacturer Code] = Vendor_1.No_) INNER JOIN Vendor ON Item.[Vendor No_] = Vendor.No_
GROUP BY [KIMO-FASHION Sales Order Line].[Model Item No_], Item.Description, Item.[Description 2], [KIMO-FASHION Sales Order Line].[Color Code], Item.[Line Code], Item.[Vendor No_], Vendor.Name, Item.[Manufacturer Code], Vendor_1.Name, Item.[Collection Code], Item.[season Code], [KIMO-FASHION Sales Order Hdr].[Assigned Sales Document No_], Customer.No_, Customer.Name, [KIMO-FASHION Sales Order Hdr].[trademark code], [KIMO-FASHION Sales Order Line].Type, [KIMO-FASHION Sales Order Hdr].[Create SO Date Time], [KIMO-FASHION Sales Order Hdr].[Release SO Date Time], [KIMO-FASHION Sales Order Line].[KIMO_FASHION SO Reference], [KIMO-FASHION Sales Order Hdr].[KIMO Document Type]
HAVING ((([KIMO-FASHION Sales Order Hdr].[Assigned Sales Document No_])="") AND (([KIMO-FASHION Sales Order Line].Type)=19 Or ([KIMO-FASHION Sales Order Line].Type)=20));

